import React, { useState } from 'react';
import {
  Divider,
  Grid,
  TextField,
  Typography,
  Button,
  Autocomplete,
  Box,
  Checkbox,
  FormControlLabel,
  Paper,
} from '@mui/material';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { DatePicker } from '@mui/x-date-pickers/DatePicker';
import { TimePicker } from '@mui/x-date-pickers/TimePicker';
import dayjs from 'dayjs';
import 'dayjs/locale/th';
import {
  CalendarToday as CalendarIcon,
  GroupAdd as GroupAddIcon,
  Business as BusinessIcon,
} from '@mui/icons-material';
dayjs.locale('th');

export default function OtRequestForm({
  Controller,
  control,
  timestamp = [],
  onSubmit,
  project = [],

  selectedEmployees,
  setSelectedEmployees,
  selectedProject,
  setSelectedProject,
}) {
  // สร้างรายการพนักงานจาก timestamp
  const employeeOptions = Array.isArray(timestamp?.rows)
    ? timestamp?.rows
        .map((item) => ({
          _id: item._id, // ใช้ id ของ timestamp
          employee_id: item.employee?._id,
          name:
            (item.employee?.firstname_th || item.employee?.firstname || '') +
            ' ' +
            (item.employee?.lastname_th || item.employee?.lastname || ''),
          department: item.employee?.department?.name || '',
          role: item.employee?.role?.name || '',
        }))
        .filter(
          (e, i, arr) => e._id && arr.findIndex((x) => x._id === e._id) === i,
        )
    : [];

  // สร้างรายการโปรเจค
  const projectOptions = Array.isArray(project?.rows)
    ? project?.rows.map((p) => ({
        _id: p._id,
        name: p.name,
        number: p.project_number,
      }))
    : [];

  // handle submit เพื่อแนบ id timestamp และ project ที่เลือก

  return (
    <Paper sx={{ p: 3, mx: 'auto' }}>
      <Typography variant="h6" fontWeight={700} gutterBottom>
        ขอ OT
      </Typography>

      <Box mb={2}>
        <Autocomplete
          multiple
          options={employeeOptions}
          getOptionLabel={(option) =>
            `${option.name} (${option.department} - ${option.role})`
          }
          value={selectedEmployees}
          onChange={(_, value) => setSelectedEmployees(value)}
          renderInput={(params) => (
            <TextField {...params} label="เลือกพนักงาน" size="small" />
          )}
          isOptionEqualToValue={(option, value) => option.id === value._id}
        />
      </Box>

      <Box mb={2}>
        <Autocomplete
          options={projectOptions}
          getOptionLabel={(option) =>
            option.number ? `${option.number} - ${option.name}` : option.name
          }
          value={selectedProject}
          onChange={(_, value) => setSelectedProject(value)}
          renderInput={(params) => (
            <TextField
              {...params}
              label="เลือกโครงการ"
              size="small"
              InputProps={{
                ...params.InputProps,
                startAdornment: (
                  <>
                    <BusinessIcon fontSize="small" sx={{ mr: 1 }} />
                    {params.InputProps.startAdornment}
                  </>
                ),
              }}
            />
          )}
          isOptionEqualToValue={(option, value) => option._id === value._id}
        />
      </Box>
      <Grid item xs={12}>
        <Divider sx={{ my: 1 }} />
      </Grid>

      <LocalizationProvider dateAdapter={AdapterDayjs} adapterLocale="th">
        <Grid container spacing={2}>
          <Grid item xs={12}>
            <Typography variant="subtitle1" fontWeight={600} gutterBottom>
              <CalendarIcon
                fontSize="small"
                sx={{ mr: 1, verticalAlign: 'middle' }}
              />
              วันที่และเวลา
            </Typography>
          </Grid>
          <Grid item xs={12} md={4}>
            <Controller
              name="date"
              control={control}
              defaultValue={dayjs()}
              render={({ field }) => (
                <DatePicker
                  label="วันที่ขอ OT"
                  value={field.value}
                  onChange={field.onChange}
                  renderInput={(params) => (
                    <TextField {...params} fullWidth size="small" />
                  )}
                  minDate={dayjs()}
                />
              )}
            />
          </Grid>
          <Grid item xs={12} md={4}>
            <Controller
              name="startTime"
              control={control}
              defaultValue={dayjs()}
              render={({ field }) => (
                <TimePicker
                  label="เวลาเริ่ม OT"
                  value={field.value}
                  onChange={field.onChange}
                  renderInput={(params) => (
                    <TextField {...params} fullWidth size="small" />
                  )}
                />
              )}
            />
          </Grid>
          <Grid item xs={12} md={4}>
            <Controller
              name="endTime"
              control={control}
              defaultValue={dayjs()}
              render={({ field }) => (
                <TimePicker
                  label="เวลาสิ้นสุด OT"
                  value={field.value}
                  onChange={field.onChange}
                  renderInput={(params) => (
                    <TextField {...params} fullWidth size="small" />
                  )}
                />
              )}
            />
          </Grid>
          <Grid item xs={12}>
            <Divider sx={{ my: 1 }} />
          </Grid>
        </Grid>
      </LocalizationProvider>
      <Box my={2}>
        <Controller
          name={'description'}
          control={control}
          defaultValue={''}
          render={({ field }) => (
            <TextField
              {...field}
              fullWidth
              multiline
              rows={3}
              label="เหตุผลในการขอ OT"
              helperText={'กรุณาระบุเหตุผลอย่างละเอียด'}
              placeholder="เช่น งานเร่งด่วน, ปิดโปรเจค, แก้ไขปัญหาระบบ"
            />
          )}
        />
      </Box>
      <Button type="submit" variant="contained" color="primary" fullWidth>
        ส่งคำขอ OT
      </Button>
    </Paper>
  );
}
