import React from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Stack,
  Chip,
  Box,
  Typography,
  Card,
  CardContent,
  useTheme,
  alpha,
  Tooltip,
  TablePagination,
} from '@mui/material';
import dayjs from 'dayjs';
import { OT_STATUS } from 'utils/constants';
import _ from 'lodash';

export default function OtRequestTable({
  otRequest,
  handleOnclickDetail,
  page,
  setPage,
  size,
  setSize,
  handleDelete,
}) {
  const theme = useTheme();
  const hasData = otRequest?.rows && otRequest.rows.length > 0;

  const calculateHours = (startTime, endTime) => {
    return dayjs(endTime).diff(dayjs(startTime), 'hour', true).toFixed(1);
  };

  const getStatusColor = (status) => {
    return OT_STATUS?.[status]?.color || 'default';
  };

  const getStatusLabel = (status) => {
    return OT_STATUS?.[status]?.status_code || status;
  };

  const handleChangePage = (event, newPage) => {
    setPage(newPage + 1);
  };
  const handleChangeRowsPerPage = (event) => {
    setSize(event.target.value);
    setPage(1);
  };

  if (!hasData) {
    return (
      <Card variant="outlined" sx={{ borderRadius: 2 }}>
        <CardContent sx={{ py: 6, textAlign: 'center' }}>
          <Typography variant="h6" color="text.secondary" gutterBottom>
            ไม่มีรายการรออนุมัติ
          </Typography>
          <Typography variant="body2" color="text.secondary">
            ไม่พบข้อมูลการขอ OT ที่รออนุมัติในขณะนี้
          </Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card variant="outlined" sx={{ borderRadius: 2 }}>
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow sx={{ bgcolor: theme.palette.primary.main }}>
              <TableCell sx={{ color: '#FFFFFF' }}>ลำดับ</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>ผู้ทำรายการ</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>พนักงาน</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>โปรเจค</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>รายละเอียด</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>ช่วงเวลา</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>ชั่วโมง</TableCell>
              <TableCell sx={{ color: '#FFFFFF' }}>
                สถานะ / ผู้อนุมัติ
              </TableCell>
              <TableCell align="center" sx={{ color: '#FFFFFF' }}>
                จัดการ
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {otRequest.rows.map((row, index) => (
              <TableRow
                key={row.id}
                sx={{
                  '&:hover': {
                    bgcolor: alpha(theme.palette.primary.main, 0.04),
                  },
                }}
              >
                {/* ลำดับ */}
                <TableCell>
                  <Typography variant="body2" fontWeight={500}>
                    {index + 1}
                  </Typography>
                </TableCell>

                {/* ผู้ทำรายการ */}
                <TableCell>
                  <Typography
                    variant="body2"
                    fontWeight={500}
                    color={theme.palette.text.primary}
                  >
                    {row?.employee?.firstname} {row?.employee?.lastname}
                  </Typography>
                </TableCell>

                {/* พนักงาน */}
                <TableCell>
                  <Box>
                    {_?.map(row?.timestamp, (e, idx) => (
                      <Typography
                        key={e?._id || idx}
                        variant="body2"
                        fontWeight={500}
                        color={theme.palette.text.secondary}
                      >
                        {idx + 1}. {e?.employee_firstname}{' '}
                        {e?.employee_lastname}
                      </Typography>
                    ))}
                  </Box>
                </TableCell>

                {/* โปรเจค */}
                <TableCell>
                  <Box>
                    <Typography
                      variant="body2"
                      fontWeight={500}
                      color={theme.palette.info.main}
                    >
                      {row?.project?.project_number || 'N/A'}
                    </Typography>
                    <Typography
                      variant="caption"
                      color={theme.palette.text.secondary}
                    >
                      {row?.project?.name || 'ไม่ระบุโปรเจค'}
                    </Typography>
                  </Box>
                </TableCell>

                {/* รายละเอียด */}
                <TableCell>
                  <Tooltip title={row?.description || 'ไม่มีรายละเอียด'}>
                    <Typography
                      variant="body2"
                      sx={{
                        maxWidth: 200,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        color: theme.palette.text.secondary,
                      }}
                    >
                      {row?.description || 'ไม่มีรายละเอียด'}
                    </Typography>
                  </Tooltip>
                </TableCell>

                {/* ช่วงเวลา */}
                <TableCell>
                  <Typography
                    variant="body2"
                    fontWeight={600}
                    color={theme.palette.success.main}
                  >
                    {dayjs(row?.startTime).format('HH:mm')} -{' '}
                    {dayjs(row?.endTime).format('HH:mm')}
                  </Typography>
                </TableCell>

                {/* จำนวนชั่วโมง */}
                <TableCell>
                  <Chip
                    label={`${calculateHours(
                      row?.startTime,
                      row?.endTime,
                    )} ชม.`}
                    size="small"
                    color="info"
                    variant="outlined"
                    sx={{ fontWeight: 500 }}
                  />
                </TableCell>

                {/* สถานะ / ผู้อนุมัติ */}
                <TableCell>
                  <Stack spacing={0.5}>
                    <Chip
                      label={getStatusLabel(row?.status)}
                      color={getStatusColor(row?.status)}
                      size="small"
                      variant="filled"
                      sx={{ fontSize: '0.7rem' }}
                    />
                    {row?.approver ? (
                      <Typography
                        variant="caption"
                        fontWeight={500}
                        sx={{
                          fontSize: '0.7rem',
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          maxWidth: 120,
                          color: theme.palette.text.secondary,
                        }}
                      >
                        {row?.approver?.firstname} {row?.approver?.lastname}
                      </Typography>
                    ) : (
                      <Typography
                        variant="caption"
                        color={theme.palette.text.disabled}
                        sx={{ fontSize: '0.7rem' }}
                      >
                        รออนุมัติ
                      </Typography>
                    )}
                  </Stack>
                </TableCell>

                {/* ปุ่มจัดการ */}
                <TableCell align="center">
                  <Button
                    variant="outlined"
                    size="small"
                    color="error"
                    onClick={() => handleDelete(row?._id)}
                  >
                    ลบ
                  </Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>

        <TablePagination
          rowsPerPageOptions={[10, 30, 40, 50, 100]}
          component="div"
          onPageChange={handleChangePage}
          onRowsPerPageChange={handleChangeRowsPerPage}
          count={otRequest?.total || 0}
          rowsPerPage={size}
          page={page - 1}
        />
      </TableContainer>
    </Card>
  );
}
